{
  "steps": [
    {
      "step_id": "cb_step_1",
      "title": "Select the CT scan",
      "simple": "Select the CT scan of the fractured bone from the available volumes.",
      "detailed": "This CT scan provides the anatomical data needed to segment and plan the reduction of the fractured long bone. Choose the volume that best shows the full extent of the fracture fragments."
    },
    {
      "step_id": "cb_step_2",
      "title": "Create a bone segmentation",
      "simple": "Switch to the Segment Editor module and create a new segmentation named 'bone_segmentation'.",
      "detailed": "The segmentation will contain the bone regions that we will extract and separate into fracture fragments. This is the initial container for all bone-related segments."
    },
    {
      "step_id": "cb_step_3",
      "title": "Add a bone segment",
      "simple": "Click the 'Add' button to create a new segment called 'bone_segment'.",
      "detailed": "This segment will hold the thresholded bone volume before we split it into individual fracture fragments. It captures the entire bone region visible on the CT."
    },
    {
      "step_id": "cb_step_4",
      "title": "Open threshold effect",
      "simple": "Click the 'Threshold' button to open the bone thresholding tool.",
      "detailed": "Thresholding uses Hounsfield unit values to separate dense bone from soft tissue. This effect will highlight the bone based on its radio-opacity in the CT scan."
    },
    {
      "step_id": "cb_step_5",
      "title": "Set the bone threshold range",
      "simple": "Adjust the threshold slider until the bone region is fully highlighted.",
      "detailed": "The threshold range determines which voxels are included as bone. Set the lower bound high enough to exclude soft tissue but low enough to include all bone fragments. You can preview the result in the slice views."
    },
    {
      "step_id": "cb_step_6",
      "title": "Apply the threshold",
      "simple": "Click 'Apply' to create the bone segment from the threshold range.",
      "detailed": "This applies the threshold effect to the bone_segment, converting the highlighted voxels into a filled segment. The segment now represents the entire visible bone as a single mass."
    },
    {
      "step_id": "cb_step_7",
      "title": "Open the Islands tool",
      "simple": "Click the 'Islands' button to access tools for separating disconnected bone fragments.",
      "detailed": "After thresholding, the bone segment may contain multiple disconnected fragments (e.g., separate pieces of the fracture). The Islands tool can identify these connected components as separate islands."
    },
    {
      "step_id": "cb_step_8",
      "title": "Split islands into separate segments",
      "simple": "Select the 'Split islands to segments' option from the Islands menu.",
      "detailed": "This option automatically separates each disconnected bone fragment into its own segment within the segmentation. Each island will become a new segment, allowing you to assign clinical labels (e.g., proximal, distal fragments)."
    },
    {
      "step_id": "cb_step_9",
      "title": "Apply the island splitting",
      "simple": "Click 'Apply' to split the bone segment into individual fragment segments.",
      "detailed": "The segmentation now contains multiple segments, each representing a different bone fragment. You can rename them later to identify the fixed reference fragment and the moving fragment."
    },
    {
      "step_id": "cb_step_10",
      "title": "Select the reference fracture fragment",
      "simple": "From the list of segments, choose the fracture fragment that will serve as the fixed reference (e.g., the proximal fragment).",
      "detailed": "The reference fragment remains stationary during reduction planning. Typically this is the main proximal fragment that aligns with the anatomical axis. The moving fragment will be repositioned relative to this reference."
    },
    {
      "step_id": "cb_step_11",
      "title": "Generate 3D model of the reference fragment",
      "simple": "Click the '3D Reconstruction (reference)' button to create a 3D surface model of the fixed fragment.",
      "detailed": "A 3D model is generated from the reference segment, allowing you to visualize the fragment in the 3D view. This model aids in spatial understanding for fracture reduction planning."
    },
    {
      "step_id": "cb_step_12",
      "title": "Select the moving fracture fragment",
      "simple": "Choose the fracture fragment that needs to be repositioned (e.g., the distal fragment).",
      "detailed": "This is the fragment that will be moved relative to the fixed reference. Selecting the correct moving segment is critical for accurate reduction planning."
    },
    {
      "step_id": "cb_step_13",
      "title": "Generate 3D model of the moving fragment",
      "simple": "Click the '3D Reconstruction (moving)' button to create a 3D surface model of the moving fragment.",
      "detailed": "A 3D model of the moving fragment is generated. You will be able to see both models in the 3D view and later manipulate the moving fragment's position."
    },
    {
      "step_id": "cb_step_14",
      "title": "Detect fracture surfaces",
      "simple": "Click 'Detect fracture surfaces' to identify the mating surfaces between fragments.",
      "detailed": "This analyzes the 3D models of both fragments and detects the fracture surfaces — the broken edges that were originally in contact. This information is used to compute the optimal reduction alignment."
    },
    {
      "step_id": "cb_step_15",
      "title": "Run reduction planning",
      "simple": "Click 'Reduction planning' to automatically compute the transform that aligns the moving fragment to its anatomical position.",
      "detailed": "The algorithm calculates the translation and rotation needed to bring the moving fragment into proper alignment with the fixed reference, based on fracture surface matching. The result is a transform that can be applied to the moving fragment."
    },
    {
      "step_id": "cb_step_16",
      "title": "Assess reduction alignment",
      "simple": "Check whether the automatic reduction is acceptable. If yes, select 'No, stop'; if you want to manually adjust, select 'Yes, adjust'.",
      "detailed": "Examine the alignment of the fragments in the 3D view. If the reduction looks anatomically correct, you can finalize. If not, you can manually fine-tune the position of the moving fragment to achieve better apposition."
    },
    {
      "step_id": "cb_step_17",
      "title": "Adjust the 3D view",
      "simple": "Rotate and zoom the 3D view to get a clear perspective on the fragment positions.",
      "detailed": "This step lets you view the fragments from all angles to assess the reduction. Use your mouse to rotate the 3D scene and zoom in/out. This visual inspection helps you decide if the automated reduction is satisfactory before proceeding."
    },
    {
      "step_id": "cb_step_18",
      "title": "Finalize moving fragment position",
      "simple": "Click 'Harden transform into moving fragment' to apply the reduction transform permanently to the moving fragment's 3D model.",
      "detailed": "This step locks the calculated alignment, incorporating the transform directly into the model's coordinates. After hardening, the moving fragment assumes its reduced position permanently in the scene."
    }
  ]
}
